use serde::{Deserialize, Serialize};

#[derive(Serialize, Deserialize, Debug, Clone, PartialEq)]
#[serde(rename_all = "lowercase")]
pub enum LanguageOrigin {
    Typescript,
    Javascript,
    Python,
    Rust,
    Go,
    Lean,
    Unknown,
}

impl Default for LanguageOrigin {
    fn default() -> Self {
        Self::Typescript
    }
}

/// Abstract representation of a function boundary regardless of original language.
#[derive(Debug, Clone)]
pub struct PolyglotFunction {
    pub name: String,
    pub params: Vec<String>,
    pub body: Vec<PolyglotStatement>,
}

#[derive(Debug, Clone)]
pub enum PolyglotStatement {
    VariableDeclaration {
        bindings: Vec<String>,
        init: Option<PolyglotExpression>,
    },
    Expression(PolyglotExpression),
    Return(Option<PolyglotExpression>),
}

#[derive(Debug, Clone)]
pub enum PolyglotExpression {
    Call {
        callee: Box<PolyglotExpression>,
        args: Vec<PolyglotExpression>,
    },
    Member {
        target: Box<PolyglotExpression>,
        property: String,
    },
    Identifier(String),
    Literal(serde_json::Value),
}

/// A parser backend that can read native source code and map it to a deterministic Betti Polyglot structure.
pub trait AstParser {
    fn parse(&self, source_text: &str, target_export_name: &str) -> Result<PolyglotFunction, String>;
}
